import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';

const Login = () => {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [rememberMe, setRememberMe] = useState(false);
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  
  const { login } = useAuth();
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setLoading(true);

    // Validation
    if (!username.trim()) {
      setError('Username is required');
      setLoading(false);
      return;
    }

    if (!password.trim()) {
      setError('Password is required');
      setLoading(false);
      return;
    }

    if (password.length < 6) {
      setError('Password must be at least 6 characters');
      setLoading(false);
      return;
    }

    try {
      // Use username as email for authentication (mock auth expects email)
      const result = await login(username, password);
      
      if (result.success) {
        // Handle remember me functionality
        if (rememberMe) {
          localStorage.setItem('rememberMe', 'true');
          localStorage.setItem('savedUsername', username);
        } else {
          localStorage.removeItem('rememberMe');
          localStorage.removeItem('savedUsername');
        }
        navigate('/dashboard');
      } else {
        setError(result.error || 'Login failed. Please try again.');
      }
    } catch (err) {
      setError('An error occurred. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  // Load saved username on mount
  React.useEffect(() => {
    const rememberMe = localStorage.getItem('rememberMe') === 'true';
    const savedUsername = localStorage.getItem('savedUsername');
    
    if (rememberMe && savedUsername) {
      setUsername(savedUsername);
      setRememberMe(true);
    }
  }, []);

  return (
    <div style={styles.pageWrapper}>
      <div style={styles.loginContainer}>
        <form id="loginForm" onSubmit={handleSubmit} novalidate style={styles.form}>
          {/* Logo Section */}
          <div style={styles.logoContainer}>
            <img
              src="https://img.icons8.com/ios-filled/50/0000FF/car.png"
              alt=""
              style={styles.logoIcon}
              aria-hidden="true"
              draggable="false"
            />
            <div>
              <div style={styles.logoTextMain}>Rent a Car</div>
              <div style={styles.logoTextSub}>Management System</div>
            </div>
          </div>

          <h2 style={styles.heading}>Welcome Back!</h2>
          <p style={styles.subtitle}>Please login to your account</p>

          {/* Error Message */}
          {error && (
            <div style={styles.errorMessage}>
              {error}
            </div>
          )}

          {/* Username Field */}
          <label htmlFor="username" style={styles.label}>Username</label>
          <div style={styles.inputGroup}>
            <span style={styles.inputIcon} aria-hidden="true">&#128100;</span>
            <input
              type="text"
              id="username"
              name="username"
              value={username}
              onChange={(e) => setUsername(e.target.value)}
              placeholder="Enter username"
              autoComplete="username"
              required
              style={styles.input}
              disabled={loading}
            />
          </div>

          {/* Password Field */}
          <label htmlFor="password" style={styles.label}>Password</label>
          <div style={styles.inputGroup}>
            <span style={styles.inputIcon} aria-hidden="true">&#128274;</span>
            <input
              type="password"
              id="password"
              name="password"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              placeholder="Enter password"
              autoComplete="current-password"
              minLength="6"
              required
              style={styles.input}
              disabled={loading}
            />
          </div>

          {/* Options Row */}
          <div style={styles.optionsRow}>
            <label style={styles.rememberMeLabel}>
              <input
                type="checkbox"
                id="rememberMe"
                name="rememberMe"
                checked={rememberMe}
                onChange={(e) => setRememberMe(e.target.checked)}
                style={styles.checkbox}
              />
              Remember me
            </label>

            <Link to="/forgot-password" style={styles.forgotPassword}>
              Forgot password?
            </Link>
          </div>

          {/* Submit Button */}
          <button 
            type="submit" 
            style={styles.btnLogin}
            disabled={loading}
          >
            {loading ? 'Logging in...' : 'Log In'}
          </button>
        </form>

        {/* Footer */}
        <div style={styles.footer}>
          <p style={styles.footerText}>
            Don't have an account?{' '}
            <Link to="/signup" style={styles.signupLink}>
              Sign Up
            </Link>
          </p>
        </div>
      </div>

      <style>{`
        @keyframes shake {
          0%, 100% { transform: translateX(0); }
          10%, 30%, 50%, 70%, 90% { transform: translateX(-5px); }
          20%, 40%, 60%, 80% { transform: translateX(5px); }
        }
        
        input:focus {
          border-color: #3b41f3 !important;
          outline: none;
        }
        
        button:hover:not(:disabled) {
          background-color: #2d31c5 !important;
        }
        
        a:hover {
          text-decoration: underline;
        }
      `}</style>
    </div>
  );
};

const styles = {
  pageWrapper: {
    minHeight: '100vh',
    margin: 0,
    fontFamily: 'Arial, sans-serif',
    background: "url('/src/assets/images/loginbg.png') no-repeat center center fixed",
    backgroundSize: 'cover',
    display: 'flex',
    justifyContent: 'center',
    alignItems: 'center',
    padding: '20px',
  },
  loginContainer: {
    background: 'white',
    padding: '30px 35px 40px 35px',
    width: '320px',
    boxShadow: '0 4px 20px rgba(0,0,0,0.1)',
    borderRadius: '6px',
    boxSizing: 'border-box',
    textAlign: 'center',
  },
  form: {
    display: 'block',
  },
  logoContainer: {
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    marginBottom: '20px',
    gap: '10px',
  },
  logoIcon: {
    width: '36px',
    height: '36px',
    filter: 'drop-shadow(0 1px 0 rgba(0,0,0,0.1))',
  },
  logoTextMain: {
    fontWeight: '600',
    fontSize: '18px',
    color: '#000',
    userSelect: 'none',
  },
  logoTextSub: {
    fontSize: '11px',
    color: '#555',
    lineHeight: '1.1',
    userSelect: 'none',
  },
  heading: {
    margin: '0 0 6px 0',
    fontWeight: '600',
    fontSize: '20px',
    color: '#000',
    userSelect: 'none',
  },
  subtitle: {
    margin: '0 0 20px 0',
    fontSize: '13px',
    color: '#555',
    userSelect: 'none',
  },
  label: {
    fontSize: '13px',
    display: 'block',
    marginBottom: '5px',
    color: '#444',
    textAlign: 'left',
    userSelect: 'none',
  },
  inputGroup: {
    position: 'relative',
    marginBottom: '15px',
  },
  inputIcon: {
    position: 'absolute',
    top: '50%',
    left: '10px',
    transform: 'translateY(-50%)',
    color: '#888',
    fontSize: '17px',
    pointerEvents: 'none',
    userSelect: 'none',
  },
  input: {
    width: '100%',
    padding: '10px 10px 10px 35px',
    border: '1.5px solid #ccc',
    borderRadius: '5px',
    fontSize: '14px',
    transition: 'border-color 0.25s ease',
    outlineOffset: '2px',
    boxSizing: 'border-box',
  },
  optionsRow: {
    display: 'flex',
    justifyContent: 'space-between',
    alignItems: 'center',
    marginBottom: '20px',
    fontSize: '13px',
    color: '#555',
  },
  rememberMeLabel: {
    userSelect: 'none',
    cursor: 'pointer',
    display: 'flex',
    alignItems: 'center',
    gap: '5px',
  },
  checkbox: {
    cursor: 'pointer',
  },
  forgotPassword: {
    color: '#3b41f3',
    textDecoration: 'none',
    fontWeight: '500',
    userSelect: 'none',
  },
  btnLogin: {
    width: '100%',
    backgroundColor: '#3b41f3',
    border: 'none',
    padding: '12px 0',
    fontSize: '15px',
    fontWeight: '600',
    color: 'white',
    borderRadius: '7px',
    cursor: 'pointer',
    transition: 'background-color 0.3s ease',
    userSelect: 'none',
  },
  errorMessage: {
    color: '#e74c3c',
    fontSize: '11px',
    marginBottom: '12px',
    textAlign: 'left',
    userSelect: 'none',
    minHeight: '14px',
  },
  footer: {
    textAlign: 'center',
    marginTop: '20px',
    paddingTop: '15px',
    borderTop: '1px solid #eee',
  },
  footerText: {
    margin: 0,
    fontSize: '13px',
    color: '#555',
  },
  signupLink: {
    color: '#3b41f3',
    textDecoration: 'none',
    fontWeight: '500',
  },
};

export default Login;
